/**
 * Writes src/mcp-apps/kairos-logo-embedded.ts from logo/kaiiros-mcp.svg so the
 * published npm package (dist-only) still ships the mark for MCP App HTML.
 */
import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.join(__dirname, '..');
const svgPath = path.join(repoRoot, 'logo', 'kaiiros-mcp.svg');
const outPath = path.join(repoRoot, 'src', 'mcp-apps', 'kairos-logo-embedded.ts');

const svg = fs.readFileSync(svgPath, 'utf8');
const body =
  '/** Generated by scripts/embed-kairos-mcp-logo.mjs from logo/kaiiros-mcp.svg */\n' +
  `export const KAIROS_LOGO_SVG = ${JSON.stringify(svg)} as const;\n`;
fs.writeFileSync(outPath, body, 'utf8');
console.log('[embed-kairos-mcp-logo] wrote', path.relative(repoRoot, outPath));
